for (const item of $input.all()) {
    const rawData = item.json.data;

    // Step 1: Extract base path for idea
    const basePathRegex = /\/idea\/[^"\/]+/;
    const basePathMatch = rawData.match(basePathRegex);

    if (!basePathMatch) {
        item.json.error = "No valid idea path found in rawData";
        continue;
    }

    const basePath = basePathMatch[0]; // e.g., /idea/ai-powered-historical-ad-style-generator

    // Step 2: Generate insight links
    const insightPages = [
        "",
        "/value-ladder",
        "/why-now",
        "/proof-signals",
        "/market-gap",
        "/execution-plan",
        "/value-equation",
        "/value-matrix",
        "/acp",
        "/community-signals",
        "/keywords"
    ];

    const insightLinks = insightPages.map(page => {
        return `https://www.ideabrowser.com${basePath}${page}`; 
    });

    // Step 3: Extract only readable text by removing HTML tags
    const cleanText = rawData.replace(/<[^>]+>/g, '').trim();

    // Step 4: Update item with results
    item.json.insightLinks = insightLinks;
    item.json.ideaPath = basePath;
    item.json.cleanText = cleanText; // 👈 This is the new key with only readable text
}

return $input.all();
